good_example:
// Test uses @Transactional which auto-rolls back — no manual cleanup needed
def testCreateUser(): Unit = {
  val user = create_user()
  assert(repo.findById(user.id).isDefined)
}

bad_example:
// Redundant — @Transactional already rolls back
def testCreateUser(): Unit = {
  val user = create_user()
  assert(repo.findById(user.id).isDefined)
  repo.delete(user.id) // unnecessary
}

